@@ -14,27 +14,5 @@
       "args": ["--mcp-server"],
       "description": "Multi-cluster Kubernetes MCP server with 22 tools for cluster management, diagnostics, and RBAC analysis"
     }
-  },
-  "skills": {
-    "k8s-health": {
-      "description": "Check health of all Kubernetes clusters",
-      "prompt": "Use the kubectl-claude MCP tools to check the health of all available Kubernetes clusters. List the clusters first, then check the health status of each one. Summarize any issues found."
-    },
-    "k8s-issues": {
-      "description": "Find issues across Kubernetes clusters",
-      "prompt": "Use the kubectl-claude MCP tools to find all issues across Kubernetes clusters. Check for: pod issues (CrashLoopBackOff, ImagePullBackOff, OOMKilled, pending), deployment issues (stuck rollouts, unavailable replicas), and warning events. Provide a summary of all problems found with recommended actions."
-    },
-    "k8s-analyze": {
-      "description": "Analyze a Kubernetes namespace",
-      "prompt": "Use the kubectl-claude MCP tools to perform a comprehensive analysis of a Kubernetes namespace. Ask the user which namespace to analyze if not specified. Use the analyze_namespace tool and provide insights on workloads, resource usage, and potential issues."
-    },
-    "k8s-security": {
-      "description": "Check for security issues in Kubernetes",
-      "prompt": "Use the kubectl-claude MCP tools to check for security issues across all namespaces. Look for: privileged containers, containers running as root, host network/PID/IPC usage, and missing resource limits. Provide a security report with severity levels and remediation recommendations."
-    },
-    "k8s-rbac": {
-      "description": "Analyze RBAC permissions for a subject",
-      "prompt": "Use the kubectl-claude MCP tools to analyze RBAC permissions. Ask the user for the subject (user, group, or service account) to analyze. Use analyze_subject_permissions to show all roles, bindings, and effective permissions. Highlight any overly permissive access."
-    }
   }
 }
